class Solution(object):
    def circularGameLosers(self, n, k):
        visited = set()
        pos = 0  # 0-indexed
        visited.add(pos)
        round_num = 1
        while True:
            pos = (pos + round_num * k) % n
            if pos in visited:
                break
            visited.add(pos)
            round_num += 1
        return [i + 1 for i in range(n) if i not in visited]
